		    if (alatDiMeja1.indexOf(self.tabung_reaksi1) !== -1 && alatDiMeja1.indexOf(self.tabung_reaksii1) !== -1) {
		        if (checkArr1[0]) checkArr1[0].visible = true;
		    }
		    // Check 2: Keduanya harus ada (penutup1 DAN penutup11)
		    if (alatDiMeja1.indexOf(self.penutup1) !== -1 && alatDiMeja1.indexOf(self.penutup11) !== -1) {
		        if (checkArr1[1]) checkArr1[1].visible = true;
		    }
