	this.frame_39 = function() {
		this.stop();
		
		// Ambil data skor
		var skor = window.skorBenar || 0;
		var totalSoal = (window.soalAcak) ? window.soalAcak.length : 10;
		var nilai = Math.round((skor / totalSoal) * 100);
		
		// Tampilkan teks ke layar
		if(this.txt_benar) this.txt_benar.text = skor.toString();
		if(this.txt_salah) this.txt_salah.text = (totalSoal - skor).toString();
		if(this.txt_total) this.txt_total.text = nilai.toString();
		
		// Logika KKM
		var kkm = 75;
		this.emot_lulus.visible = false;
		this.emot_tidaklulus.visible = false;
		this.txt_lulus.visible = false;
		this.txt_tidaklulus.visible = false;
		
		if (nilai >= kkm) {
		    this.emot_lulus.visible = true;
		    this.txt_lulus.visible = true;
		} else {
		    this.emot_tidaklulus.visible = true;
		    this.txt_tidaklulus.visible = true;
		}
		
		// ================= LOGIKA RESTART =================
		this.btn_restart.cursor = "pointer";
		
		// 🔴 TAMBAHAN: Jika nilai 100, tombol restart hilang
		if (nilai === 100) {
		    this.btn_restart.visible = false;
		    this.btn_restart.mouseEnabled = false;
		} else {
		    this.btn_restart.visible = true;
		    this.btn_restart.mouseEnabled = true;
		
		    this.btn_restart.on("click", () => {
		        // Reset data kuis agar bisa diulang
		        window.indeks = 0;
		        window.skorBenar = 0;
		
		        // Pergi ke Frame 28
		        this.gotoAndStop(28); 
		    });
		}
	}

